template<typename F>

class FixPoint {

public:

    explicit constexpr FixPoint(F&& f) : f_(forward<F>(f)) {}



    template<typename... Args>

    constexpr decltype(auto) operator()(Args&&... args) const {

        return f_(*this, forward<Args>(args)...);

    }



private:

